#include<bits/stdc++.h>
using namespace std;
vector<int> e[65538];
int out[65538], in[65538];
int main() {
	int n;
	cin >> n;
	for (int i = 1; i <= n; i++) {
		int flag = 0;
		while (1) {
			int x;
			cin >> x;
			if (x == 0) break;
			e[x].push_back(i);
			out[x]++;
			in[i]++;
			flag = 1;
		}
		if (!flag ) {
			e[0].push_back(i);
			out[0]++;
			in[i]++;
		}
	}
	for (int i = 1; i <= n; i++) {
		int tout[65538], tin[65538],ans=0;
		memcpy(tout, out, sizeof(int) * (n+1));
		memcpy(tin, in, sizeof(int) * (n+1));
		stack<int> s;
		s.push(i);
		while(!s.empty()){
			int x=s.top();
            s.pop();
			for(int i=0;i<e[x].size();i++){
				tin[e[x][i]]--;
				tout[x]--;
				if(tin[e[x][i]]==0){
					ans++;
					s.push(e[x][i]);
				}
			}
		}
		cout<<ans<<"\n";
	}
	return 0;
}
